SELECT MAX(rating) AS highest_rating
FROM product_reviews
WHERE product_id = 0;

SELECT name
FROM customers
WHERE customer_id IN (
  SELECT customer_id
  FROM orders
  WHERE order_id IN (
    SELECT order_id
    FROM returns
  )
);

SELECT DISTINCT name
FROM customers
WHERE customer_id IN (
  SELECT customer_id
  FROM product_reviews
);
